const raw = $input.first().json.body || '';
const docMeta = $input.first().json;
const cleaned = raw
  .replace(/\s+/g, ' ')
  .replace(/[|]/g, 'I')
  .replace(/0(?=[a-zA-Z])/g, 'O')
  .trim();
return [{ json: {
  raw_text: raw,
  cleaned_text: cleaned,
  char_count: cleaned.length,
  word_count: cleaned.split(' ').length,
  doc_id: docMeta.doc_id,
  source: docMeta.source,
  file_url: docMeta.file_url,
  received_at: docMeta.received_at,
  requester_email: docMeta.requester_email
}}];

const item = $input.first().json;
const raw = item.choices?.[0]?.message?.content || '{}';
let cls = {};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  cls = m ? JSON.parse(m[0]) : {};
} catch(e) {
  cls = { type: 'UNKNOWN', confidence: 0, urgency: 'ROUTINE', language: 'fr' };
}
return [{ json: {
  ...item,
  doc_type: cls.type || 'UNKNOWN',
  doc_confidence: cls.confidence || 0,
  doc_urgency: cls.urgency || 'ROUTINE',
  doc_language: cls.language || 'fr'
}}];

const item = $input.first().json;
const raw = item.choices?.[0]?.message?.content || '{}';
let extracted = {};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  extracted = m ? JSON.parse(m[0]) : { extraction_error: true };
} catch(e) {
  extracted = { extraction_error: true, raw_response: raw };
}

const errors = [];
if (!extracted.patient?.full_name) errors.push('MISSING_PATIENT_NAME');
if (extracted.extraction_error) errors.push('GPT_PARSE_ERROR');

const hasCritical = (
  item.doc_urgency === 'STAT' ||
  extracted.critical_values?.length > 0 ||
  extracted.critical_finding === true ||
  extracted.is_narcotics === true
);

return [{ json: {
  ...item,
  extracted_data: extracted,
  validation_errors: errors,
  is_valid: errors.length === 0,
  has_critical: hasCritical
}}];

const item = $input.first().json;
const summary = item.choices?.[0]?.message?.content || 'Summary unavailable';
return [{ json: { ...item, clinical_summary: summary } }];
